import{_ as t,o,c as s,ai as n}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"System Prompt","description":"","frontmatter":{"summary":"What the OpenSoul system prompt contains and how it is assembled","read_when":["Editing system prompt text, tools list, or time/heartbeat sections","Changing workspace bootstrap or skills injection behavior"],"title":"System Prompt"},"headers":[],"relativePath":"concepts/system-prompt.md","filePath":"concepts/system-prompt.md","lastUpdated":1771906665000}'),a={name:"concepts/system-prompt.md"};function i(r,e,l,d,c,p){return o(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="system-prompt" tabindex="-1"><a class="header-anchor" href="#system-prompt">#</a> System Prompt</h1><p>OpenSoul builds a custom system prompt for every agent run. The prompt is <strong>OpenSoul-owned</strong> and does not use the p-coding-agent default prompt.</p><p>The prompt is assembled by OpenSoul and injected into each agent run.</p><h2 id="structure" tabindex="-1"><a class="header-anchor" href="#structure">#</a> Structure</h2><p>The prompt is intentionally compact and uses fixed sections:</p><ul><li><strong>Tooling</strong>: current tool list + short descriptions.</li><li><strong>Safety</strong>: short guardrail reminder to avoid power-seeking behavior or bypassing oversight.</li><li><strong>Skills</strong> (when available): tells the model how to load skill instructions on demand.</li><li><strong>OpenSoul Self-Update</strong>: how to run <code>config.apply</code> and <code>update.run</code>.</li><li><strong>Workspace</strong>: working directory (<code>agents.defaults.workspace</code>).</li><li><strong>Documentation</strong>: local path to OpenSoul docs (repo or npm package) and when to read them.</li><li><strong>Workspace Files (injected)</strong>: indicates bootstrap files are included below.</li><li><strong>Sandbox</strong> (when enabled): indicates sandboxed runtime, sandbox paths, and whether elevated exec is available.</li><li><strong>Current Date &amp; Time</strong>: user-local time, timezone, and time format.</li><li><strong>Reply Tags</strong>: optional reply tag syntax for supported providers.</li><li><strong>Heartbeats</strong>: heartbeat prompt and ack behavior.</li><li><strong>Runtime</strong>: host, OS, node, model, repo root (when detected), thinking level (one line).</li><li><strong>Reasoning</strong>: current visibility level + /reasoning toggle hint.</li></ul><p>Safety guardrails in the system prompt are advisory. They guide model behavior but do not enforce policy. Use tool policy, exec approvals, sandboxing, and channel allowlists for hard enforcement; operators can disable these by design.</p><h2 id="prompt-modes" tabindex="-1"><a class="header-anchor" href="#prompt-modes">#</a> Prompt modes</h2><p>OpenSoul can render smaller system prompts for sub-agents. The runtime sets a <code>promptMode</code> for each run (not a user-facing config):</p><ul><li><code>full</code> (default): includes all sections above.</li><li><code>minimal</code>: used for sub-agents; omits <strong>Skills</strong>, <strong>Memory Recall</strong>, <strong>OpenSoul Self-Update</strong>, <strong>Model Aliases</strong>, <strong>User Identity</strong>, <strong>Reply Tags</strong>, <strong>Messaging</strong>, <strong>Silent Replies</strong>, and <strong>Heartbeats</strong>. Tooling, <strong>Safety</strong>, Workspace, Sandbox, Current Date &amp; Time (when known), Runtime, and injected context stay available.</li><li><code>none</code>: returns only the base identity line.</li></ul><p>When <code>promptMode=minimal</code>, extra injected prompts are labeled <strong>Subagent Context</strong> instead of <strong>Group Chat Context</strong>.</p><h2 id="workspace-bootstrap-injection" tabindex="-1"><a class="header-anchor" href="#workspace-bootstrap-injection">#</a> Workspace bootstrap injection</h2><p>Bootstrap files are trimmed and appended under <strong>Project Context</strong> so the model sees identity and profile context without needing explicit reads:</p><ul><li><code>AGENTS.md</code></li><li><code>SOUL.md</code></li><li><code>TOOLS.md</code></li><li><code>IDENTITY.md</code></li><li><code>USER.md</code></li><li><code>HEARTBEAT.md</code></li><li><code>BOOTSTRAP.md</code> (only on brand-new workspaces)</li></ul><p>Large files are truncated with a marker. The max per-file size is controlled by <code>agents.defaults.bootstrapMaxChars</code> (default: 20000). Missing files inject a short missing-file marker.</p><p>Internal hooks can intercept this step via <code>agent:bootstrap</code> to mutate or replace the injected bootstrap files (for example swapping <code>SOUL.md</code> for an alternate persona).</p><p>To inspect how much each injected file contributes (raw vs injected, truncation, plus tool schema overhead), use <code>/context list</code> or <code>/context detail</code>. See <a href="/docs/concepts/context">Context</a>.</p><h2 id="time-handling" tabindex="-1"><a class="header-anchor" href="#time-handling">#</a> Time handling</h2><p>The system prompt includes a dedicated <strong>Current Date &amp; Time</strong> section when the user timezone is known. To keep the prompt cache-stable, it now only includes the <strong>time zone</strong> (no dynamic clock or time format).</p><p>Use <code>session_status</code> when the agent needs the current time; the status card includes a timestamp line.</p><p>Configure with:</p><ul><li><code>agents.defaults.userTimezone</code></li><li><code>agents.defaults.timeFormat</code> (<code>auto</code> | <code>12</code> | <code>24</code>)</li></ul><p>See <a href="/docs/date-time">Date &amp; Time</a> for full behavior details.</p><h2 id="skills" tabindex="-1"><a class="header-anchor" href="#skills">#</a> Skills</h2><p>When eligible skills exist, OpenSoul injects a compact <strong>available skills list</strong> (<code>formatSkillsForPrompt</code>) that includes the <strong>file path</strong> for each skill. The prompt instructs the model to use <code>read</code> to load the SKILL.md at the listed location (workspace, managed, or bundled). If no skills are eligible, the Skills section is omitted.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;available_skills&gt;</span></span>
<span class="line"><span>  &lt;skill&gt;</span></span>
<span class="line"><span>    &lt;name&gt;...&lt;/name&gt;</span></span>
<span class="line"><span>    &lt;description&gt;...&lt;/description&gt;</span></span>
<span class="line"><span>    &lt;location&gt;...&lt;/location&gt;</span></span>
<span class="line"><span>  &lt;/skill&gt;</span></span>
<span class="line"><span>&lt;/available_skills&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>This keeps the base prompt small while still enabling targeted skill usage.</p><h2 id="documentation" tabindex="-1"><a class="header-anchor" href="#documentation">#</a> Documentation</h2><p>When available, the system prompt includes a <strong>Documentation</strong> section that points to the local OpenSoul docs directory (either <code>docs/</code> in the repo workspace or the bundled npm package docs) and also notes the public mirror, source repo, community Discord, and ClawHub (<a href="https://clawhub.com" target="_blank" rel="noreferrer">https://clawhub.com</a>) for skills discovery. The prompt instructs the model to consult local docs first for OpenSoul behavior, commands, configuration, or architecture, and to run <code>opensoul status</code> itself when possible (asking the user only when it lacks access).</p>`,29)])])}const g=t(a,[["render",i]]);export{h as __pageData,g as default};
